#define AMB_TEMP 80.0f

__kernel void hotspot(int iteration,
                      __global const float *power,
                      __global const float *temp_src,
                      __global float *temp_dst,
                      int col,
                      int row,
                      int borderCols,
                      int borderRows,
                      float Cap,
                      float Rx,
                      float Ry,
                      float Rz,
                      float step)
{
    const int tx = get_local_id(0);
    const int ty = get_local_id(1);
    const int bx = get_group_id(0);
    const int by = get_group_id(1);

    const int small_block_cols = BLOCK_SIZE - (borderCols << 1);
    const int small_block_rows = BLOCK_SIZE - (borderRows << 1);

    const int x = bx * small_block_cols + tx - borderCols;
    const int y = by * small_block_rows + ty - borderRows;

    const int lidx = ty * BLOCK_SIZE + tx;
    const int gidx = y * col + x;

    __local float temp0[BLOCK_SIZE * BLOCK_SIZE];
    __local float temp1[BLOCK_SIZE * BLOCK_SIZE];
    __local float power_local[BLOCK_SIZE * BLOCK_SIZE];

    if (x >= 0 && x < col && y >= 0 && y < row) {
        temp0[lidx] = temp_src[gidx];
        power_local[lidx] = power[gidx];
    } else {
        temp0[lidx] = 0.0f;
        power_local[lidx] = 0.0f;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    /* Host code uses step = PRECISION / max_slope; OpenMP source uses /1000.0 as well. */
    const float Cap_1 = (step * 0.001f) / Cap;
    const float Rx_1 = 1.0f / Rx;
    const float Ry_1 = 1.0f / Ry;
    const float Rz_1 = 1.0f / Rz;

    for (int i = 0; i < iteration; i++) {
        __local float *src = (i & 1) ? temp1 : temp0;
        __local float *dst = (i & 1) ? temp0 : temp1;

        if (tx >= (i + 1) && tx <= (BLOCK_SIZE - i - 2) &&
            ty >= (i + 1) && ty <= (BLOCK_SIZE - i - 2) &&
            x >= 0 && x < col && y >= 0 && y < row) {

            const float center = src[lidx];
            float delta = power_local[lidx] + (AMB_TEMP - center) * Rz_1;

            if (y == 0) {
                delta += (src[(ty + 1) * BLOCK_SIZE + tx] - center) * Ry_1;
            } else if (y == row - 1) {
                delta += (src[(ty - 1) * BLOCK_SIZE + tx] - center) * Ry_1;
            } else {
                delta += (src[(ty + 1) * BLOCK_SIZE + tx] +
                          src[(ty - 1) * BLOCK_SIZE + tx] -
                          2.0f * center) * Ry_1;
            }

            if (x == 0) {
                delta += (src[ty * BLOCK_SIZE + (tx + 1)] - center) * Rx_1;
            } else if (x == col - 1) {
                delta += (src[ty * BLOCK_SIZE + (tx - 1)] - center) * Rx_1;
            } else {
                delta += (src[ty * BLOCK_SIZE + (tx + 1)] +
                          src[ty * BLOCK_SIZE + (tx - 1)] -
                          2.0f * center) * Rx_1;
            }

            dst[lidx] = center + Cap_1 * delta;
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    __local float *final_temp = (iteration & 1) ? temp1 : temp0;

    if (tx >= borderCols && tx < (BLOCK_SIZE - borderCols) &&
        ty >= borderRows && ty < (BLOCK_SIZE - borderRows) &&
        x >= 0 && x < col && y >= 0 && y < row) {
        temp_dst[gidx] = final_temp[lidx];
    }
}
